{
  "verses": [
    {
      "n": 14,
      "column": "left",
      "text": "Tee akpleſch ſawu Rihtu\nprett manni/ ka weens plehſige\nun ruhzans Lauwa."
    },
    {
      "n": 15,
      "column": "left",
      "text": "Es eſinn iſgahſts kaſſeh-\ndens/ wiſſi manni Kauli irr iſ-\nlohtiſchees/ manna Sirds irr\nmannas Meetâs/ ka iſkaufehts\nWaskis."
    },
    {
      "n": 16,
      "column": "left",
      "text": "Mans Speheſ irr iſkal-\ntis/ ka Pohda Gabbals/ un man-\nna Mehle peelihp pee manna\nSchohda/ un tu nolez manni\nNahweg Pihschlês."
    },
    {
      "n": 17,
      "column": "left",
      "text": "Jo Sunxi irr ap man-\nnim apſtahjutchi/ un to Laun-\ndarritajn Draudse irr fahrt man-\nni mettuſees / tee irr mannas\nRohkas un mannas Rahjas iſ.\nurbuſchi."
    },
    {
      "n": 18,
      "column": "left",
      "text": "Es warretu wiſſus man-\nnus Kaulus ſkaitiht / bet wiſſi\nſkattahs un uſluhko mann\n( libgfſmodamees. )"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Tee dalla mannas Dreſ-\nbes ſawâ Starpâ/ un mett Kan-\nlins pahr mannu Apgehrbu."
    },
    {
      "n": 20,
      "column": "left",
      "text": "Bet tu ak KUNGS!\nne eſſi tahnu/ mans Stiprums/\nſteidſees man par Paligu."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Iſglahb mannu Dweh-\nfeli no Sohbina/ mannu Ween-\ntuli no Sunxu Warras."
    },
    {
      "n": 22,
      "column": "left",
      "text": "Iſpeſti mannu no ta Lau-\nwa Rihkles/ un no to Weenrad-\nschu Raggeem paklaufidams\nmann iſglahbi."
    },
    {
      "n": 23,
      "column": "left",
      "text": "Es fluddinaschtu ſawu\nWahrdn manneem Brahteem /\nes flaweschu tevi ſtarp tahs\nDraundſes,"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Suwejeet to Kuſſu\nkas juhs winnu bihſtatees/\nJehkaba Oſimmuns lai wi\ngohda/ un bihſteetees winnu\nIsraêta Oſimmuns."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Jo wiſſch ne irr n\nnajs nedſ apſmehtis ta Veb-\nApbehdiſchann / nedſ\nWaigu no ta paſlehpts/ un\ntas winnu peenoze / tad w\npaklaufija."
    },
    {
      "n": 26,
      "column": "right",
      "text": "No tevis es dſeeda\neeſſch tahs feelas Draudſes\nmaſſatchu mannas Apfohli-\nnas preeſſch teem / kas wi\nbihſtahs."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Tee Behdigee ehdihe\npee.ehdihs/ un kas to Kuſſu\nmekle / winnu flawehs / j\nSirds muhſchtgi dſihwohs."
    },
    {
      "n": 28,
      "column": "right",
      "text": "Wiſſi Semines Ba\npeeminnehs/ un atgreesiſees\nta KUNGA/ un wiſſas B\nnu Tautas winna Preel\npeeluhaſ."
    },
    {
      "n": 29,
      "column": "right",
      "text": "Jo tam KUNGAM\nderr ta Walſtiba/ un w\nwalda ſtarp teem Pagancee"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Wiſſi Trekuee wirs\nmes ehdihs un peeluhgs/ w\nkas Pihschlês gull/ paklann\nwinna Breekſcha/ ir tee/\nſawu Dſihwibu ne zeent."
    },
    {
      "n": 31,
      "column": "right",
      "text": "Winnam buhs D\nmuns/ kas winnam kalp\nno ta KUNGA taps fluddin\nlihds zittceem Raddeem."
    },
    {
      "n": 32,
      "column": "right",
      "text": "Tee atnahſs un pa-\ndinahs winna Daſnibu /"
    }
  ],
  "confidence": "high",
  "notes": ""
}
